--
-- Table structure for table `analytics_snapshots`
--

CREATE TABLE `analytics_snapshots` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `brand_id` bigint(20) UNSIGNED NOT NULL,
  `snapshot_date` date NOT NULL,
  `total_reach` bigint(20) UNSIGNED NOT NULL DEFAULT 0,
  `engagement_rate` decimal(5,2) NOT NULL DEFAULT 0.00,
  `link_clicks` int(10) UNSIGNED NOT NULL DEFAULT 0,
  `followers_gained` int(11) NOT NULL DEFAULT 0,
  `posts_published` int(10) UNSIGNED NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Table structure for table `brands`
--

CREATE TABLE `brands` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `user_id` bigint(20) UNSIGNED NOT NULL,
  `plan_id` bigint(20) UNSIGNED DEFAULT NULL,
  `name` varchar(255) NOT NULL,
  `slug` varchar(255) NOT NULL,
  `website` varchar(500) DEFAULT NULL,
  `industry` varchar(100) DEFAULT NULL,
  `country` varchar(100) NOT NULL DEFAULT 'India',
  `language` varchar(50) NOT NULL DEFAULT 'English',
  `tone` varchar(100) DEFAULT NULL,
  `founded_year` smallint(5) UNSIGNED DEFAULT NULL,
  `short_description` text DEFAULT NULL,
  `logo_path` varchar(500) DEFAULT NULL,
  `setup_step` tinyint(3) UNSIGNED NOT NULL DEFAULT 1 COMMENT '1=business, 2=assets, 3=social',
  `setup_completed_at` timestamp NULL DEFAULT NULL,
  `sources_updated_at` timestamp NULL DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

