(25, 1, NULL, 'sabkhoj  my brand', 'sabkhoj-my-brand', 'https://www.sabkhoj.in/', 'Other', 'India', 'English', 'Professional & authoritative', NULL, '\"Sabkhoj Informatics Pvt. Ltd. | Web Design | Software Solutions | Digital Marketing Established in 2014, Sabkhoj Informatics Pvt. Ltd. is a trusted name in web development, software solutions, and digital marketing services across India. We specialize in helping businesses grow through tailored business development strategies, e-commerce solutions, custom software, website design & development, and online advertising. Our expert team also offers software training and internet marketing services to ensure your brand stands out in the digital world. Whether you\'re a startup or an established company, we deliver innovative and result-driven solutions that enhance your online presence and customer experience.\"', 'brands/logos/IvJP0KakuWj9HfPtEH7gjPtx2kzAEfyygqgxwpzp.png', 5, '2026-07-03 15:33:11', NULL, 1, '2026-07-07 12:12:11', '2026-07-03 15:29:26', '2026-07-07 12:12:11'),
