(185, 27, 'web-design-carousel-slide-1.jpg', 'brands/27/content_library/ai-images/web-design-carousel-slide-1-ba6b838a-2b87-46c1-ac7a-74ae182bbf74.jpg', 'local', 'image', 'image/jpeg', 231001, 'indexed', '2026-07-07 12:41:09', '{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A vibrant, clean website homepage displayed on a desktop monitor, a tablet, and a smartphone, all seamlessly connected by a subtle, glowing line. The design is modern and user-friendly. Text overlay: \'1. Responsive Design: Flawless on Every Device\'\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"e3c49d64-ded4-4010-b2a1-4b5225ca48c1\",\"slot\":0}', NULL, '2026-07-07 12:41:09', '2026-07-07 12:41:09'),
(186, 27, 'web-design-carousel-slide-2.jpg', 'brands/27/content_library/ai-images/web-design-carousel-slide-2-bbad57c1-ab09-4096-89ff-572976c41dca.jpg', 'local', 'image', 'image/jpeg', 157922, 'indexed', '2026-07-07 12:41:21', '{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A close-up of a website\'s \'Add to Cart\' button, glowing subtly, with a clear, concise headline next to it. A stopwatch icon is faintly visible in the background, suggesting speed. Text overlay: \'2. Clear Call-to-Actions: Guiding Your Visitors\'\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"e3c49d64-ded4-4010-b2a1-4b5225ca48c1\",\"slot\":1}', NULL, '2026-07-07 12:41:21', '2026-07-07 12:41:21'),
(187, 27, 'web-design-carousel-slide-3.jpg', 'brands/27/content_library/ai-images/web-design-carousel-slide-3-088387ed-eef5-43fb-9733-14553ed7cdcf.jpg', 'local', 'image', 'image/jpeg', 305766, 'indexed', '2026-07-07 12:41:32', '{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A split screen. On one side, a website with a chaotic layout and tiny, unreadable text. On the other side, the same website with a clean, organized layout, ample white space, and large, readable fonts. Text overlay: \'3. Intuitive User Experience: Effortless Navigation\'\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"e3c49d64-ded4-4010-b2a1-4b5225ca48c1\",\"slot\":2}', NULL, '2026-07-07 12:41:32', '2026-07-07 12:41:32'),
(188, 27, 'web-design-carousel-slide-4.jpg', 'brands/27/content_library/ai-images/web-design-carousel-slide-4-0803e226-0da4-4b32-ac90-a153bd162144.jpg', 'local', 'image', 'image/jpeg', 235678, 'indexed', '2026-07-07 12:41:44', '{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A stylized bar graph showing increasing conversion rates with a magnifying glass icon hovering over it, emphasizing detail and optimization. A speech bubble with a question mark hovers over a user icon, then transitions to a satisfied user with a checkmark. Text overlay: \'4. Optimized Performance: Speed & SEO\' and \'5. Compelling Content: Engaging Your Audience\'. Small Sabkhoj logo in the corner. Final call to action: \'Ready for a High-Converting Website? Contact Sabkhoj Today!\'\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"e3c49d64-ded4-4010-b2a1-4b5225ca48c1\",\"slot\":3}', NULL, '2026-07-07 12:41:44', '2026-07-07 12:41:44'),
(189, 27, 'carousel-educational-slides-slide-1.jpg', 'brands/27/content_library/ai-images/carousel-educational-slides-slide-1-20585544-9d1d-489f-bfa4-86eb3cd7f8cd.jpg', 'local', 'image', 'image/jpeg', 259954, 'indexed', '2026-07-07 12:49:41', '{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A professional, clean image of a magnifying glass hovering over a world map, with digital lines connecting various cities. The magnifying glass highlights \'India\'. Text on the image is minimal, focusing on a strong, modern aesthetic. The color palette is corporate blue and white with subtle gold accents.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"95a8115c-f21d-4b9c-8e96-2a12ce1ad054\",\"slot\":0}', NULL, '2026-07-07 12:49:41', '2026-07-07 12:49:41'),
(190, 27, 'carousel-educational-slides-slide-2.jpg', 'brands/27/content_library/ai-images/carousel-educational-slides-slide-2-1a44ead7-b9c1-4a65-b69b-bed5d5a30f81.jpg', 'local', 'image', 'image/jpeg', 239474, 'indexed', '2026-07-07 12:49:57', '{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A split image. On one side, a graph showing an upward trend with various digital marketing icons (SEO, PPC, Social Media logos). On the other side, a sleek laptop displaying a modern website design. The overall feel is dynamic and growth-oriented. Colors are bright and engaging, representing different digital channels.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"95a8115c-f21d-4b9c-8e96-2a12ce1ad054\",\"slot\":1}', NULL, '2026-07-07 12:49:57', '2026-07-07 12:49:57'),
