(193, 27, 'lead-gen-reel-script.mp4', 'brands/27/content_library/ai-videos/lead-gen-reel-script-baa77842-abd0-45a8-b3be-953f09c8383f.mp4', 'local', 'video', 'video/mp4', 2733238, 'indexed', '2026-07-07 13:10:52', '{\"source\":\"content_library\",\"library_type\":\"reel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A busy, overwhelmed business owner sits at a cluttered desk, head in hands. Camera slowly zooms in on their frustrated face. Text: \\\"Struggling to find new clients?\\\" A bright, energetic Sabkhoj dashboard appears, glowing. Camera pans across the clean interface. Text: \\\"Sabkhoj: Your lead generation solution.\\\" The business owner smiles confidently, shaking hands with a new client in a modern office. Camera pulls back to show a thriving, bustling workspace. Text: \\\"Transform your business with Sabkho\",\"ai_provider\":\"openrouter\",\"ai_model\":\"google\\/veo-3.1-lite\",\"duration_seconds\":8}', NULL, '2026-07-07 13:10:52', '2026-07-07 13:10:52'),
