(308, 33, 'explaining-tdf-service-slide-1.jpg', 'brands/33/content_library/ai-images/explaining-tdf-service-slide-1-a9ee2bc2-3c5d-4416-9604-e36cdf44730a.jpg', 'local', 'image', 'image/jpeg', 219232, 'indexed', '2026-07-14 14:14:45', '{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A professional, clean, and modern image. The central focus is a bold title \'What is TDF?\' in a sans-serif font. Below, a brief, concise definition: \'TDF (Trusted Digital Framework) is a secure and interoperable digital identity and data sharing platform.\' The background is a subtle, abstract digital pattern, reminiscent of network connections, in shades of blue and grey, similar to the professional aesthetic of \'creative_1_linkedin.png\'.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"c5f3eb7a-313d-45f5-a11b-289dd8b855b0\",\"slot\":0}', NULL, '2026-07-14 14:14:45', '2026-07-14 14:14:45'),
(309, 33, 'explaining-tdf-service-slide-2.jpg', 'brands/33/content_library/ai-images/explaining-tdf-service-slide-2-7076f36c-304e-49c1-9ecf-100bd6470152.jpg', 'local', 'image', 'image/jpeg', 189312, 'indexed', '2026-07-14 14:15:00', '{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A professional, clean, and modern image highlighting \'Key Features\'. Three distinct icons, each representing a feature: 1. A shield with a checkmark (for Security), 2. Interlocking gears (for Interoperability), 3. A magnifying glass over data (for Data Control). Each icon is accompanied by a short, descriptive text: \'Enhanced Security\', \'Seamless Interoperability\', \'User-Centric Data Control\'. The background maintains the subtle digital pattern in blue\\/grey tones, consistent with \'creative_1_linkedin.png\'.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"c5f3eb7a-313d-45f5-a11b-289dd8b855b0\",\"slot\":1}', NULL, '2026-07-14 14:15:00', '2026-07-14 14:15:00'),
(310, 33, 'explaining-tdf-service-slide-3.jpg', 'brands/33/content_library/ai-images/explaining-tdf-service-slide-3-9e5c6bdc-488f-4e05-8b8f-466a46f8cc33.jpg', 'local', 'image', 'image/jpeg', 153920, 'indexed', '2026-07-14 14:15:14', '{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A professional, clean, and modern image focusing on \'Benefits\'. Three distinct icons, each representing a benefit: 1. A person\'s silhouette with a padlock (for Trust), 2. Two hands shaking (for Collaboration), 3. A upward-trending arrow graph (for Efficiency). Each icon is accompanied by a short, descriptive text: \'Increased Trust\', \'Streamlined Collaboration\', \'Improved Operational Efficiency\'. The background maintains the subtle digital pattern in blue\\/grey tones, consistent with \'creative_1_linkedin.png\'.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"c5f3eb7a-313d-45f5-a11b-289dd8b855b0\",\"slot\":2}', NULL, '2026-07-14 14:15:14', '2026-07-14 14:15:14'),
(311, 33, 'explaining-tdf-service-slide-4.jpg', 'brands/33/content_library/ai-images/explaining-tdf-service-slide-4-95bda440-ad31-47ef-8a90-65020692c217.jpg', 'local', 'image', 'image/jpeg', 201686, 'indexed', '2026-07-14 14:15:26', '{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A professional, clean, and modern image with a call to action. The central element is a large, prominent text: \'Empowering Your Digital Future with TDF\'. Below, a smaller text: \'Learn more about how TDF can transform your digital interactions.\' A subtle button-like graphic with text \'Visit Our Website\' or \'Contact Us\' could be integrated without being an actual clickable button. The background is a slightly more pronounced, but still abstract, digital network pattern, in shades of blue and grey, maintaining the professional aesthetic of \'creative_1_linkedin.png\'.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"c5f3eb7a-313d-45f5-a11b-289dd8b855b0\",\"slot\":3}', NULL, '2026-07-14 14:15:26', '2026-07-14 14:15:26'),
