(24, 27, 'Professional & authoritative', 'Businesses in India seeking digital marketing, web development, and business growth solutions.', 'Sabkhoj offers a wide range of services including Business Development, Android/IOS Development, Domain and Hosting, Responsive Web Design, SEO, Paid Search, Social Media Marketing, Consulting, Lead Generation, and Brand Reputation Management.', '[\"Business Directory\",\"SEO\",\"Local Business\",\"Digital Marketing\",\"India\",\"Web Design\",\"Lead Generation\",\"Mobile App Development\",\"Brand Reputation\"]', '{\"business\":{\"name\":\"sabkhojbrand\",\"website\":\"https:\\/\\/www.sabkhoj.in\\/\",\"industry\":\"SaaS \\/ Tech\",\"country\":\"India\",\"language\":\"English\",\"tone\":\"Professional & authoritative\",\"description\":\"According to TopTenReviews in 2018, as well as many other 3rd party review sites and publications we always comes out on top. We\\u2019re a leading Internet Digital Marketing Company who offers SEO, Paid Search, Social Media, ConsultingLead Generation, Brand Reputation Management, and Web Design Services.\",\"products_services\":\"Business Development\\r\\nAndroid \\/ IOS Development\\r\\nDomain And Hosting\\r\\nResponsive Web\",\"target_audience\":null,\"keywords\":[\"Business Directory\",\"SEO\",\"Local Business\",\"Digital Marketing\",\"India\"]},\"assets\":[{\"id\":174,\"name\":\"logosabkhoj.png\",\"type\":\"image\",\"path\":\"brands\\/27\\/assets\\/MeHGrpq6xYP0qbT5CosT0m1EOCCXfkXXkLeTOnnj.png\",\"disk\":\"local\",\"metadata\":{\"source\":\"wizard_step_2\"}},{\"id\":175,\"name\":\"Brand logo\",\"type\":\"logo\",\"path\":\"brands\\/logos\\/8g5juBoTyoLQq1UzAJYT5ssP84vvseDhivLTS63M.png\",\"disk\":\"public\",\"metadata\":{\"source\":\"brand_create\"}},{\"id\":179,\"name\":\"image-hero-brand-visual.jpg\",\"type\":\"image\",\"path\":\"brands\\/27\\/content_library\\/ai-images\\/image-hero-brand-visual-262ddf2e-c12d-4e49-8cbc-832b137e69e7.jpg\",\"disk\":\"local\",\"metadata\":{\"source\":\"content_library\",\"library_type\":\"image\",\"from_content_suggestion\":true,\"generation_prompt\":\"Photorealistic, clean, and professional hero shot of a modern workspace with a sleek laptop displaying \\\"Sabkhoj Digital Solutions\\\" on screen, subtle warm lighting, authoritative and trustworthy mood.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\"}},{\"id\":180,\"name\":\"image-hero-brand-visual.jpg\",\"type\":\"image\",\"path\":\"brands\\/27\\/content_library\\/ai-images\\/image-hero-brand-visual-0fec7e36-d3b8-4d5a-82fc-ec09e84e9bf2.jpg\",\"disk\":\"local\",\"metadata\":{\"source\":\"content_library\",\"library_type\":\"image\",\"from_content_suggestion\":true,\"generation_prompt\":\"Professional, authoritative photorealistic image of a sleek, modern office interior with a conference table, bathed in soft, natural light, conveying sophisticated calm.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\"}},{\"id\":181,\"name\":\"image-product-showcase.jpg\",\"type\":\"image\",\"path\":\"brands\\/27\\/content_library\\/ai-images\\/image-product-showcase-f133eca4-d79f-4681-8362-049f35323edc.jpg\",\"disk\":\"local\",\"metadata\":{\"source\":\"content_library\",\"library_type\":\"image\",\"from_content_suggestion\":true,\"generation_prompt\":\"Modern Indian office, diverse team collaborating around a glowing holographic table displaying digital marketing graphs and web layouts, natural light streaming through large windows, energetic and innovative mood.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\"}},{\"id\":182,\"name\":\"image-behind-the-scenes.jpg\",\"type\":\"image\",\"path\":\"brands\\/27\\/content_library\\/ai-images\\/image-behind-the-scenes-b0c09455-eb85-48ac-ab5b-9da3f261af4d.jpg\",\"disk\":\"local\",\"metadata\":{\"source\":\"content_library\",\"library_type\":\"image\",\"from_content_suggestion\":true,\"generation_prompt\":\"Indian digital marketing and web development team collaborating intently around a brightly lit monitor in a modern, sun-drenched office. Professional, focused, and collaborative mood.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\"}},{\"id\":183,\"name\":\"image-customer-story.jpg\",\"type\":\"image\",\"path\":\"brands\\/27\\/content_library\\/ai-images\\/image-customer-story-b787fd5f-bf48-4436-a4b8-049b3b005e5d.jpg\",\"disk\":\"local\",\"metadata\":{\"source\":\"content_library\",\"library_type\":\"image\",\"from_content_suggestion\":true,\"generation_prompt\":\"Photorealistic image: A beaming Indian business owner in a modern office, giving a thumbs-up, with a sleek laptop displaying a successful website design in the background. Soft, professional studio lighting, conveying confidence and achievement.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\"}},{\"id\":184,\"name\":\"image-seasonal-campaign.jpg\",\"type\":\"image\",\"path\":\"brands\\/27\\/content_library\\/ai-images\\/image-seasonal-campaign-e915edbe-f3b1-4b9c-8abc-7e91907ca48f.jpg\",\"disk\":\"local\",\"metadata\":{\"source\":\"content_library\",\"library_type\":\"image\",\"from_content_suggestion\":true,\"generation_prompt\":\"Photorealistic image: A diverse group of Indian business professionals smiling, collaborating around a tablet displaying \\\"Sabkhoj: Digital Solutions for Your Business Growth\\\" with a vibrant, sunlit background. Modern office setting, natural lighting, optimistic and professional mood.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\"}},{\"id\":185,\"name\":\"web-design-carousel-slide-1.jpg\",\"type\":\"image\",\"path\":\"brands\\/27\\/content_library\\/ai-images\\/web-design-carousel-slide-1-ba6b838a-2b87-46c1-ac7a-74ae182bbf74.jpg\",\"disk\":\"local\",\"metadata\":{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A vibrant, clean website homepage displayed on a desktop monitor, a tablet, and a smartphone, all seamlessly connected by a subtle, glowing line. The design is modern and user-friendly. Text overlay: \'1. Responsive Design: Flawless on Every Device\'\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"e3c49d64-ded4-4010-b2a1-4b5225ca48c1\",\"slot\":0}},{\"id\":186,\"name\":\"web-design-carousel-slide-2.jpg\",\"type\":\"image\",\"path\":\"brands\\/27\\/content_library\\/ai-images\\/web-design-carousel-slide-2-bbad57c1-ab09-4096-89ff-572976c41dca.jpg\",\"disk\":\"local\",\"metadata\":{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A close-up of a website\'s \'Add to Cart\' button, glowing subtly, with a clear, concise headline next to it. A stopwatch icon is faintly visible in the background, suggesting speed. Text overlay: \'2. Clear Call-to-Actions: Guiding Your Visitors\'\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"e3c49d64-ded4-4010-b2a1-4b5225ca48c1\",\"slot\":1}},{\"id\":187,\"name\":\"web-design-carousel-slide-3.jpg\",\"type\":\"image\",\"path\":\"brands\\/27\\/content_library\\/ai-images\\/web-design-carousel-slide-3-088387ed-eef5-43fb-9733-14553ed7cdcf.jpg\",\"disk\":\"local\",\"metadata\":{\"source\":\"content_library\",\"library_type\":\"carousel\",\"from_content_suggestion\":true,\"generation_prompt\":\"A split screen. On one side, a website with a chaotic layout and tiny, unreadable text. On the other side, the same website with a clean, organized layout, ample white space, and large, readable fonts. Text overlay: \'3. Intuitive User Experience: Effortless Navigation\'\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\",\"carousel\":true,\"carousel_group\":\"e3c49d64-ded4-4010-b2a1-4b5225ca48c1\",\"slot\":2}},{\"id\":188,\"name\":\"web-design-carousel-slide-4.