--
-- Table structure for table `content_items`
--

CREATE TABLE `content_items` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `brand_id` bigint(20) UNSIGNED NOT NULL,
  `folder_id` bigint(20) UNSIGNED DEFAULT NULL,
  `parent_id` bigint(20) UNSIGNED DEFAULT NULL,
  `ai_generation_request_id` bigint(20) UNSIGNED DEFAULT NULL,
  `content_type` enum('post','carousel','reel_script','image_caption','hashtags','thirty_day_plan','thread') NOT NULL,
  `platform` enum('facebook','instagram','linkedin','x','youtube','snapchat','pinterest','threads','google_business','multi') NOT NULL,
  `title` varchar(500) DEFAULT NULL,
  `body` longtext NOT NULL,
  `status` enum('draft','approved','scheduled','published','failed') NOT NULL DEFAULT 'draft',
  `variation_number` tinyint(3) UNSIGNED DEFAULT 1,
  `generation_prompt` text DEFAULT NULL,
  `scheduled_at` timestamp NULL DEFAULT NULL,
  `published_at` timestamp NULL DEFAULT NULL,
  `external_post_id` varchar(255) DEFAULT NULL,
  `external_post_url` varchar(500) DEFAULT NULL,
  `reach` int(10) UNSIGNED DEFAULT 0,
  `engagement_rate` decimal(5,2) DEFAULT NULL,
  `metadata` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`metadata`)),
  `deleted_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

