(165, 26, NULL, NULL, NULL, 'reel_script', 'instagram', 'PPC Success Reel', 'Subject: Stressed business owner, then thriving business owner. Camera: Dynamic transition from shaky handheld to smooth tracking shot. Setting: Dark, messy office transitioning to bright, modern office with busy team. Lighting: Dim, cool tones to warm, vibrant light. Mood: Despair to triumphant success.', 'draft', 1, 'Develop a reel script for Instagram showcasing a before-and-after scenario of a business struggling with online visibility and then thriving after using Sabkhoj\'s PPC services. Incorporate the \'ppc-success-reel.mp4\' video asset and maintain an energetic, inspiring tone. End with a strong call to action to DM for details.', NULL, NULL, NULL, NULL, 0, NULL, '{\"from_content_suggestion\":true,\"suggestion_category\":\"reel\",\"suggestion_title\":\"PPC Success Reel\",\"asset_id\":235,\"video_url\":\"http:\\/\\/localhost\\/aindracmo\\/public\\/app\\/brand\\/assets\\/235\",\"video_prompt\":\"Subject: Stressed business owner, then thriving business owner. Camera: Dynamic transition from shaky handheld to smooth tracking shot. Setting: Dark, messy office transitioning to bright, modern office with busy team. Lighting: Dim, cool tones to warm, vibrant light. Mood: Despair to triumphant success.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"google\\/veo-3.1-lite\"}', NULL, '2026-07-11 11:34:49', '2026-07-11 11:34:49'),
(166, 26, NULL, NULL, NULL, 'carousel', 'facebook', 'Web Design Carousel', 'A user looking frustrated at a poorly designed, cluttered website on a desktop computer. The website has broken images and overlapping text. Question on image: \'Is your website turning visitors away?\'', 'draft', 1, 'Design a 5-slide Facebook carousel post illustrating the importance of professional web design. Each slide should feature a different aspect (e.g., user experience, mobile responsiveness, branding) and include an engaging question. The final slide should promote Sabkhoj\'s web design services with a link to their portfolio.', NULL, NULL, NULL, NULL, 0, NULL, '{\"from_content_suggestion\":true,\"suggestion_category\":\"carousel\",\"suggestion_title\":\"Web Design Carousel\",\"carousel_group\":\"0ddcd2b6-e0f9-407e-a849-b0690c6a1092\",\"carousel_asset_ids\":[236,237,238,239],\"asset_id\":236,\"carousel_slide_prompts\":[\"A user looking frustrated at a poorly designed, cluttered website on a desktop computer. The website has broken images and overlapping text. Question on image: \'Is your website turning visitors away?\'\",\"A split image showing a smartphone. One side shows a website that is perfectly scaled and easy to navigate on mobile. The other side shows the same website, but it\'s tiny, unreadable, and requires excessive pinching and zooming. Question on image: \'Is your site ready for every screen?\'\",\"A vibrant, modern, and cohesive website homepage design with a clear logo and consistent color scheme, radiating professionalism and trust. Question on image: \'Does your brand shine online?\'\",\"An infographic illustrating increased conversion rates and lower bounce rates due to good web design. Happy customers are shown completing online purchases or filling out forms. Question on image: \'Ready to boost your business goals?\'\"],\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\"}', NULL, '2026-07-11 11:35:42', '2026-07-11 11:35:42'),
