(178, 31, NULL, NULL, NULL, 'post', 'facebook', 'Intro to \'test\' product', 'नमस्ते दोस्तों! 👋 क्या आप भी अपनी टी-शर्ट्स को लेकर परेशान रहते हैं? 🤔 बार-बार धोने से उनका रंग फीका पड़ रहा है या कपड़ा खराब हो रहा है?\n\nतो अब और नहीं! 🤩 हम आपके लिए लाए हैं हमारा नया प्रोडक्ट जो खास आपकी प्यारी टी-शर्ट्स के लिए बना है! ✨ इसे इस्तेमाल करने के बाद आपकी टी-शर्ट्स दिखेंगी एकदम नई जैसी, और उनकी चमक भी बनी रहेगी लंबे समय तक! 👕💖\n\nअपनी टी-शर्ट्स को दें नया जीवन! 🚀 अभी sabkhoj.in पर जाएं और जानें कैसे! 💻\n\n#SabKhoj #TeesLove #NewProduct #TShirtCare #Fashion #Hindi #OnlineShopping', 'draft', 1, 'Create a casual and friendly Facebook post in Hindi introducing our \'test\' product. Focus on a key benefit for \'tees\' and include a call to action to visit our website sabkhoj.in.', NULL, NULL, NULL, NULL, 0, NULL, '{\"from_content_suggestion\":true,\"suggestion_category\":\"caption\",\"suggestion_title\":\"Intro to \'test\' product\",\"ai_provider\":\"openrouter\",\"ai_model\":\"google\\/gemini-2.5-flash\"}', NULL, '2026-07-13 14:06:23', '2026-07-13 14:06:23'),
(179, 31, NULL, NULL, NULL, 'post', 'x', 'Image: hero brand visual', 'Young, diverse friends laughing, sharing a soda on a sunny park bench, vibrant colors, soft natural light, cheerful mood.', 'draft', 1, 'Create an image post brief for dev cmo: a clean hero visual showcasing the brand identity. Style: Casual & friendly. Audience: The target audience is described as \'tees\'.. Include layout, colors, and overlay text suggestions.', NULL, NULL, NULL, NULL, 0, NULL, '{\"from_content_suggestion\":true,\"suggestion_category\":\"image\",\"suggestion_title\":\"Image: hero brand visual\",\"asset_id\":252,\"image_prompt\":\"Young, diverse friends laughing, sharing a soda on a sunny park bench, vibrant colors, soft natural light, cheerful mood.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\"}', NULL, '2026-07-13 14:06:38', '2026-07-13 14:06:38'),
(180, 31, NULL, NULL, NULL, 'reel_script', 'instagram', 'Why \'tees\' love us', 'Gen Z influencer, close-up, holding a tee, casual kitchen setting, soft natural light, happy. \"Hey guys, mera naam Tee hai, aur yeh test service toh kamaal hai! Isne meri life badal di. Definitely try it!\" Upbeat music.', 'draft', 1, 'Develop a short, engaging Instagram Reel script in Hindi featuring a \'tee\' talking about how our \'test\' service has helped them. Keep the tone casual and friendly, and suggest upbeat background music.', NULL, NULL, NULL, NULL, 0, NULL, '{\"from_content_suggestion\":true,\"suggestion_category\":\"reel\",\"suggestion_title\":\"Why \'tees\' love us\",\"asset_id\":253,\"video_url\":\"http:\\/\\/localhost\\/aindracmo\\/public\\/app\\/brand\\/assets\\/253\",\"video_prompt\":\"Gen Z influencer, close-up, holding a tee, casual kitchen setting, soft natural light, happy. \\\"Hey guys, mera naam Tee hai, aur yeh test service toh kamaal hai! Isne meri life badal di. Definitely try it!\\\" Upbeat music.\",\"ai_provider\":\"openrouter\",\"ai_model\":\"google\\/veo-3.1-lite\"}', NULL, '2026-07-13 14:08:29', '2026-07-13 14:08:29'),
(181, 31, NULL, NULL, NULL, 'carousel', 'instagram', 'Carousel: educational slides', 'A cool, casual tee with a graphic design of a stylized \'test\' product. The tee is draped over a skateboard or a comfy chair, with a slightly blurred background of a vibrant, youthful room. Warm, inviting lighting.', 'draft', 1, 'Design a 5-slide Instagram carousel for dev cmo educating The target audience is described as \'tees\'. about The brand offers \'test\' products and services.. Each slide: heading + 2–3 lines + visual direction. Tone: Casual & friendly.', NULL, NULL, NULL, NULL, 0, NULL, '{\"from_content_suggestion\":true,\"suggestion_category\":\"carousel\",\"suggestion_title\":\"Carousel: educational slides\",\"carousel_group\":\"7bbac3de-6d1a-4f97-befb-bf18feac9182\",\"carousel_asset_ids\":[254,255,256,257],\"asset_id\":254,\"carousel_slide_prompts\":[\"A cool, casual tee with a graphic design of a stylized \'test\' product. The tee is draped over a skateboard or a comfy chair, with a slightly blurred background of a vibrant, youthful room. Warm, inviting lighting.\",\"A close-up of a hand (wearing a friendship bracelet) holding a \'test\' product, showing off its unique texture or a small, interesting detail. The background is a soft-focus, sunny outdoor setting, like a park or a beach.\",\"A group of diverse teens laughing and interacting while subtly using or holding \'test\' products. The scene is a hangout spot \\u2013 maybe a cafe, a rec room, or a park bench. Dynamic composition, capturing candid moments.\",\"An abstract, playful illustration representing the benefits of \'test\' products. Think bright colors, geometric shapes, and whimsical elements that convey ease, fun, or problem-solving without being too literal. A sense of movement and energy.\"],\"ai_provider\":\"openrouter\",\"ai_model\":\"black-forest-labs\\/flux.2-pro\"}', NULL, '2026-07-13 14:09:19', '2026-07-13 14:09:19'),
